                  {servDD && (<div className="absolute top-full left-0 mt-2 glass-strong rounded-2xl p-3 min-w-[280px] shadow-xl z-50">
                    {L.services.items.map((s,si)=>(<button key={si} onClick={()=>{nav(s.link);setServDD(false);}} className="flex items-center gap-3 w-full px-4 py-3 rounded-xl hover:bg-white/5 transition-colors text-left"><div className="text-cyan-400">{s.icon}</div><div><div className="text-sm font-medium text-white">{s.title}</div><div className="text-xs text-gray-500">{s.stat} {s.statLabel}</div></div></button>))}
                  </div>)}
